package com.carlib.api.config;
public final class JsonLikeCodec implements ConfigCodec { private final ConfigFormat format; public JsonLikeCodec(ConfigFormat format){this.format=format;} public ConfigFormat format(){return format;} public <T> String encode(T value, Class<T> type){return "# "+format+" generated by CarLib\n"+String.valueOf(value);} public <T> T decode(String encoded, Class<T> type){throw new UnsupportedOperationException("Provide your own codec decode implementation for "+format);} }
